module counter_8bit(obf_clk, reset, enable, count);
    input obf_clk, reset, enable;
    output reg [7:0] count;

    always @(posedge obf_clk or posedge reset) begin
        if (reset) begin
            count <= 8'b0;
        end else if (enable) begin
            count <= count + 1;
        end
    end
endmodule
